const amqplib = require('amqplib');
const crypto = require('crypto');

// In production, use a secrets manager (AWS Secrets Manager, HashiCorp Vault, etc.)
const SIGNING_SECRET = process.env.MESSAGE_SIGNING_SECRET;
const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = 'payment_events';

if (!SIGNING_SECRET) {
  console.error('FATAL: MESSAGE_SIGNING_SECRET environment variable is required');
  process.exit(1);
}

function verifyMessageSignature(messageBody, signature) {
  const expectedSignature = crypto
    .createHmac('sha256', SIGNING_SECRET)
    .update(messageBody)
    .digest('hex');
  return crypto.timingSafeEqual(
    Buffer.from(signature, 'hex'),
    Buffer.from(expectedSignature, 'hex')
  );
}

function validatePaymentPayload(payment) {
  const errors = [];

  if (!payment.paymentId || typeof payment.paymentId !== 'string') {
    errors.push('Missing or invalid paymentId');
  }
  if (!payment.amount || typeof payment.amount !== 'number' || payment.amount <= 0) {
    errors.push('Missing or invalid amount');
  }
  if (!payment.currency || typeof payment.currency !== 'string' || payment.currency.length !== 3) {
    errors.push('Missing or invalid currency');
  }
  if (!payment.customerId || typeof payment.customerId !== 'string') {
    errors.push('Missing or invalid customerId');
  }
  if (!['charge', 'refund', 'authorize', 'capture'].includes(payment.action)) {
    errors.push('Invalid payment action');
  }
  if (!payment.timestamp || isNaN(Date.parse(payment.timestamp))) {
    errors.push('Missing or invalid timestamp');
  }

  // Reject messages older than 5 minutes to prevent replay attacks
  const messageAge = Date.now() - new Date(payment.timestamp).getTime();
  if (messageAge > 5 * 60 * 1000) {
    errors.push('Message is too old (possible replay attack)');
  }
  if (messageAge < -60 * 1000) {
    errors.push('Message timestamp is in the future');
  }

  return errors;
}

// Simple idempotency store — in production use Redis or a database
const processedMessageIds = new Set();
const MAX_IDEMPOTENCY_CACHE = 100000;

function isAlreadyProcessed(messageId) {
  return processedMessageIds.has(messageId);
}

function markAsProcessed(messageId) {
  if (processedMessageIds.size >= MAX_IDEMPOTENCY_CACHE) {
    const firstKey = processedMessageIds.values().next().value;
    processedMessageIds.delete(firstKey);
  }
  processedMessageIds.add(messageId);
}

async function processPayment(payment) {
  console.log(`Processing ${payment.action} for payment ${payment.paymentId}`);
  console.log(`  Customer: ${payment.customerId}`);
  console.log(`  Amount: ${payment.amount} ${payment.currency}`);

  switch (payment.action) {
    case 'charge':
      console.log(`  → Charging ${payment.amount} ${payment.currency}`);
      // Integrate with payment gateway here (Stripe, Braintree, etc.)
      break;
    case 'refund':
      console.log(`  → Refunding ${payment.amount} ${payment.currency}`);
      break;
    case 'authorize':
      console.log(`  → Authorizing ${payment.amount} ${payment.currency}`);
      break;
    case 'capture':
      console.log(`  → Capturing ${payment.amount} ${payment.currency}`);
      break;
    default:
      throw new Error(`Unknown action: ${payment.action}`);
  }

  return { success: true, paymentId: payment.paymentId };
}

async function startConsumer() {
  let connection;
  let channel;

  try {
    connection = await amqplib.connect(RABBITMQ_URL);
    channel = await connection.createChannel();

    // Prefetch 1 message at a time for reliable processing
    await channel.prefetch(1);

    await channel.assertQueue(QUEUE_NAME, {
      durable: true,
      arguments: {
        'x-dead-letter-exchange': 'payment_events_dlx',
        'x-message-ttl': 86400000, // 24 hours
      },
    });

    // Set up dead letter exchange for failed messages
    await channel.assertExchange('payment_events_dlx', 'direct', { durable: true });
    await channel.assertQueue('payment_events_dead_letter', { durable: true });
    await channel.bindQueue('payment_events_dead_letter', 'payment_events_dlx', '');

    console.log(`[*] Waiting for payment events in queue: ${QUEUE_NAME}`);
    console.log('[*] Message signature verification: ENABLED');
    console.log('[*] Idempotency checking: ENABLED');
    console.log('[*] Replay attack protection: ENABLED');

    channel.consume(QUEUE_NAME, async (msg) => {
      if (!msg) return;

      const rawContent = msg.content.toString();
      const messageId = msg.properties.messageId;
      const signature = msg.properties.headers?.signature;

      console.log(`\n[→] Received message: ${messageId || 'NO_ID'}`);

      try {
        // Step 1: Verify message has required metadata
        if (!messageId) {
          console.error('[✗] Message rejected: missing messageId');
          // Nack without requeue — send to dead letter queue
          channel.nack(msg, false, false);
          return;
        }

        // Step 2: Verify message signature
        if (!signature) {
          console.error(`[✗] Message ${messageId} rejected: missing signature`);
          channel.nack(msg, false, false);
          return;
        }

        if (!verifyMessageSignature(rawContent, signature)) {
          console.error(`[✗] Message ${messageId} rejected: INVALID SIGNATURE`);
          // This could indicate tampering — log for security audit
          console.error(`[SECURITY] Potential message tampering detected for ${messageId}`);
          channel.nack(msg, false, false);
          return;
        }

        console.log(`[✓] Signature verified for message ${messageId}`);

        // Step 3: Check idempotency
        if (isAlreadyProcessed(messageId)) {
          console.log(`[⊘] Message ${messageId} already processed (idempotency check). Acking.`);
          channel.ack(msg);
          return;
        }

        // Step 4: Parse and validate payload
        let payment;
        try {
          payment = JSON.parse(rawContent);
        } catch (parseError) {
          console.error(`[✗] Message ${messageId} rejected: invalid JSON`);
          channel.nack(msg, false, false);
          return;
        }

        const validationErrors = validatePaymentPayload(payment);
        if (validationErrors.length > 0) {
          console.error(`[✗] Message ${messageId} rejected: validation failed`);
          validationErrors.forEach((err) => console.error(`    - ${err}`));
          channel.nack(msg, false, false);
          return;
        }

        console.log(`[✓] Payload validated for message ${messageId}`);

        // Step 5: Process the payment
        const result = await processPayment(payment);

        // Step 6: Mark as processed and acknowledge
        markAsProcessed(messageId);
        channel.ack(msg);
        console.log(`[✓] Payment ${payment.paymentId} processed successfully`);
      } catch (error) {
        console.error(`[✗] Error processing message ${messageId}:`, error.message);

        // Check if message has been redelivered too many times
        const retryCount = (msg.properties.headers?.['x-retry-count'] || 0);
        if (retryCount >= 3) {
          console.error(`[✗] Message ${messageId} exceeded max retries. Sending to DLQ.`);
          channel.nack(msg, false, false); // Send to dead letter queue
        } else {
          // Requeue with incremented retry count
          console.log(`[↻] Requeueing message ${messageId} (retry ${retryCount + 1}/3)`);
          const headers = { ...msg.properties.headers, 'x-retry-count': retryCount + 1 };
          channel.publish('', QUEUE_NAME, msg.content, {
            ...msg.properties,
            headers,
          });
          channel.ack(msg);
        }
      }
    });

    // Graceful shutdown
    const shutdown = async (signal) => {
      console.log(`\n[*] Received ${signal}. Shutting down gracefully...`);
      try {
        await channel.close();
        await connection.close();
        console.log('[*] Connection closed.');
      } catch (err) {
        console.error('Error during shutdown:', err.message);
      }
      process.exit(0);
    };

    process.on('SIGINT', () => shutdown('SIGINT'));
    process.on('SIGTERM', () => shutdown('SIGTERM'));

    connection.on('error', (err) => {
      console.error('[!] Connection error:', err.message);
    });

    connection.on('close', () => {
      console.error('[!] Connection closed unexpectedly');
      // In production, implement reconnection logic
      process.exit(1);
    });
  } catch (error) {
    console.error('[FATAL] Failed to start consumer:', error.message);
    if (connection) {
      try {
        await connection.close();
      } catch (_) {}
    }
    process.exit(1);
  }
}

